-- Check total videos count
SELECT COUNT(*) as total_videos FROM videos;

-- Check videos per category
SELECT c.name, COUNT(v.id) as video_count 
FROM categories c 
LEFT JOIN videos v ON c.id = v.category_id 
GROUP BY c.id, c.name
ORDER BY c.sort_order;

-- Sample: Check first 5 Connections videos
SELECT v.id, v.title, c.name as category 
FROM videos v 
JOIN categories c ON v.category_id = c.id 
WHERE c.name = 'Connections' 
ORDER BY v.sort_order 
LIMIT 5;
